// Función para limpiar el texto JSON de posibles caracteres problemáticos
function limpiarJSON(texto) {
  // Remover bloques de código markdown si existen
  texto = texto.replace(/```json\n?/g, '').replace(/```\n?/g, '');

  // Remover espacios en blanco al inicio y final
  texto = texto.trim();

  return texto;
}

// Función para extraer el JSON del output del agente
function extraerJSONDeOutput(item) {
  try {
    // Navegar por la estructura del output
    const output = item.output;

    if (!output || !Array.isArray(output) || output.length === 0) {
      throw new Error('Output vacío o inválido');
    }

    // Obtener el primer elemento del array output
    const mensaje = output[0];

    // Verificar que tenga la estructura esperada
    if (!mensaje.content || !Array.isArray(mensaje.content) || mensaje.content.length === 0) {
      throw new Error('Contenido del mensaje vacío o inválido');
    }

    // Obtener el texto del contenido
    const contenido = mensaje.content[0];

    if (!contenido.text) {
      throw new Error('No se encontró texto en el contenido');
    }

    // Limpiar y parsear el JSON
    const textoLimpio = limpiarJSON(contenido.text);
    const copysJSON = JSON.parse(textoLimpio);

    return {
      success: true,
      copys: copysJSON,
      metadata: {
        message_id: mensaje.id,
        status: mensaje.status,
        role: mensaje.role
      }
    };

  } catch (error) {
    return {
      success: false,
      error: error.message,
      raw_text: item.output?.[0]?.content?.[0]?.text || 'No se pudo extraer el texto'
    };
  }
}

