// Función para extraer URLs del objeto datos_publicacion o directamente del item
function extraerUrls(item) {
  const urls = [];
  const datos = item.datos_publicacion || item;

  for (let i = 1; i <= 10; i++) {
    const urlKey = `url_${i}`;
    if (datos[urlKey]) {
      urls.push(datos[urlKey]);
    }
  }

  return urls;
}

// Función para extraer nombres de imágenes
function extraerNombresImagenes(item) {
  const nombres = [];
