// ============================================================================
// NODO CODE: GENERAR ENDPOINTS PARA PUBLICACIÓN EN REDES SOCIALES
// ============================================================================
// Basado en Meta Graph API v24.0 - Documentación oficial
// INPUT: Item 0 = JSON con config + credenciales, Items 1-10 = Binarios opcionales
// OUTPUT: Items separados por red social listos para HTTP Request
// ============================================================================

const items = $input.all();

if (items.length < 1) {
    throw new Error('Se requiere al menos 1 input con JSON de configuración');
}

// ===== EXTRAER DATOS =====
const jsonData = items[0].json;

// Las URLs públicas son críticas - Meta API las requiere
const urls = jsonData.urls || [];
const redes = Array.isArray(jsonData.redes_sociales) ? jsonData.redes_sociales : [];
const tipoContenido = jsonData.tipo_contenido; // "imagen" o "video"
const cantidadArchivos = jsonData.cantidad_archivos || urls.length;
const output = [];

// ===== VALIDACIONES =====
if (!jsonData) {
    throw new Error('No se encontró JSON en el primer input');
}

if (!tipoContenido) {
    throw new Error('El campo tipo_contenido es requerido ("imagen" o "video")');
}

if (cantidadArchivos === 0 || urls.length === 0) {
    throw new Error('No se encontraron URLs de archivos');
}

// ===== FUNCIÓN PRINCIPAL: GENERAR ITEM POR RED SOCIAL =====
function generarItemPorRed(red, formato) {
    const item = {
        // Metadata para el Switch node
        red_social: red.toLowerCase(),
        formato: formato,
        tipo_contenido: tipoContenido,
        cantidad_archivos: cantidadArchivos,

        // Configuración HTTP Request
        method: 'POST',
        url: '',
        headers: {},
        qs: {}, // Query String parameters
        body: {},

        // URLs de medios
        media_urls: urls,

        // Metadata adicional
        chat_id: jsonData.chat_id,
        message_id: jsonData.message_id,
        es_programado: jsonData.es_programado || false,
        fecha_publicacion: jsonData.fecha_publicacion,
        hora_publicacion: jsonData.hora_publicacion,

        // Flags especiales para flujos complejos
        requiere_loop: false,
        es_carrusel: false,
        paso_actual: 1,
        total_pasos: 1
    };

    // ===== INSTAGRAM =====
    if (red.toLowerCase() === 'instagram') {
        const igUserId = jsonData.facebook_instagram?.ig_user_id;
        const igToken = jsonData.facebook_instagram?.token;

        if (!igUserId || !igToken) {
            throw new Error('Faltan credenciales de Instagram: ig_user_id o token');
        }

        item.headers = {
            'Content-Type': 'application/json'
        };
        item.qs = {
            access_token: igToken
        };

        // CARRUSEL (2-10 imágenes o videos)
        if (formato === 'Carrusel' && cantidadArchivos >= 2 && cantidadArchivos <= 10) {
            item.formato_detallado = 'instagram_carousel';
            item.es_carrusel = true;
            item.requiere_loop = true;
            item.total_pasos = 3; // Crear items individuales → Crear container carrusel → Publicar

            // PASO 1: Crear containers individuales (se procesará en loop)
            item.url = `https://graph.facebook.com/v24.0/${igUserId}/media`;
            item.loop_config = {
                tipo: 'crear_items_carrusel',
                endpoint: `https://graph.facebook.com/v24.0/${igUserId}/media`,
                body_template: {
                    is_carousel_item: true,
                    image_url: '{{URL_PLACEHOLDER}}', // Se reemplazará en el loop
                    access_token: igToken
                }
            };

            // PASO 2 y 3: Se configurarán después del loop
            item.carrusel_config = {
                endpoint_container: `https://graph.facebook.com/v24.0/${igUserId}/media`,
                endpoint_publish: `https://graph.facebook.com/v24.0/${igUserId}/media_publish`,
                caption: jsonData.instagram_carrusel?.caption || '',
                access_token: igToken
            };

        // REELS (video)
        } else if (formato === 'Reels' && tipoContenido === 'video') {
            item.formato_detallado = 'instagram_reel';
            item.total_pasos = 2; // Crear container → Publicar

            // PASO 1: Crear container
            item.url = `https://graph.facebook.com/v24.0/${igUserId}/media`;
            item.body = {
                media_type: 'REELS',
                video_url: urls[0],
                caption: jsonData.instagram_reel?.caption || '',
                share_to_feed: true
            };

            // PASO 2: Publicar (se hará después)
            item.publish_config = {
                endpoint: `https://graph.facebook.com/v24.0/${igUserId}/media_publish`,
                access_token: igToken
            };

        // FEED POST (imagen única)
        } else if (formato === 'Feed Post' && tipoContenido === 'imagen') {
            item.formato_detallado = 'instagram_feed_image';
            item.total_pasos = 2;

            // PASO 1: Crear container
            item.url = `https://graph.facebook.com/v24.0/${igUserId}/media`;
            item.body = {
                media_type: 'IMAGE',
                image_url: urls[0],
                caption: jsonData.instagram_feed_post?.caption || ''
            };

            // PASO 2: Publicar
            item.publish_config = {
                endpoint: `https://graph.facebook.com/v24.0/${igUserId}/media_publish`,
                access_token: igToken
            };

        // FEED VIDEO POST
        } else if (formato === 'Feed Video Post' && tipoContenido === 'video') {
            item.formato_detallado = 'instagram_feed_video';
            item.total_pasos = 2;

            item.url = `https://graph.facebook.com/v24.0/${igUserId}/media`;
            item.body = {
                media_type: 'VIDEO',
                video_url: urls[0],
                caption: jsonData.instagram_feed_post?.caption || ''
            };

            item.publish_config = {
                endpoint: `https://graph.facebook.com/v24.0/${igUserId}/media_publish`,
                access_token: igToken
            };

        // STORIES (imagen o video)
        } else if (formato === 'Stories') {
            item.formato_detallado = 'instagram_story';
            item.total_pasos = 2;

            item.url = `https://graph.facebook.com/v24.0/${igUserId}/media`;
            item.body = {
                media_type: 'STORIES',
                [tipoContenido === 'video' ? 'video_url' : 'image_url']: urls[0]
            };

            item.publish_config = {
                endpoint: `https://graph.facebook.com/v24.0/${igUserId}/media_publish`,
                access_token: igToken
            };
        }
    }

    // ===== FACEBOOK =====
    else if (red.toLowerCase() === 'facebook') {
        const fbPageId = jsonData.facebook_instagram?.ig_page_id;
        const fbToken = jsonData.facebook_instagram?.token;

        if (!fbPageId || !fbToken) {
            throw new Error('Faltan credenciales de Facebook: ig_page_id o token');
        }

        item.headers = {
            'Content-Type': 'application/json'
        };
        item.qs = {
            access_token: fbToken
        };

        // PHOTO POST - Foto única o múltiples
        if (formato === 'Photo Post' && tipoContenido === 'imagen') {

            if (cantidadArchivos === 1) {
                // FOTO ÚNICA - Publicación directa
                item.formato_detallado = 'facebook_photo_single';
                item.url = `https://graph.facebook.com/v24.0/${fbPageId}/photos`;
                item.body = {
                    url: urls[0],
                    message: jsonData.facebook_organico?.copy_completo || '',
                    published: true
                };

            } else {
                // MÚLTIPLES FOTOS - Similar a carrusel
                item.formato_detallado = 'facebook_photos_multiple';
                item.requiere_loop = true;
                item.total_pasos = 2; // Subir fotos → Crear post con attached_media

                // PASO 1: Subir cada foto (en loop)
                item.loop_config = {
                    tipo: 'subir_fotos_facebook',
                    endpoint: `https://graph.facebook.com/v24.0/${fbPageId}/photos`,
                    body_template: {
                        url: '{{URL_PLACEHOLDER}}',
                        published: false, // No publicar aún
                        access_token: fbToken
                    }
                };

                // PASO 2: Crear post con todas las fotos
                item.post_config = {
                    endpoint: `https://graph.facebook.com/v24.0/${fbPageId}/feed`,
                    message: jsonData.facebook_organico?.copy_completo || '',
                    access_token: fbToken
                };
            }

        // ALBUM
        } else if (formato === 'Album' && tipoContenido === 'imagen') {
            item.formato_detallado = 'facebook_album';
            item.requiere_loop = true;
            item.total_pasos = 3; // Crear álbum → Subir fotos → Publicar álbum

            // PASO 1: Crear álbum
            item.url = `https://graph.facebook.com/v24.0/${fbPageId}/albums`;
            item.body = {
                name: jsonData.facebook_album?.titulo || 'Álbum',
                message: jsonData.facebook_album?.mensaje || jsonData.facebook_organico?.copy_completo || ''
            };

            // PASO 2: Subir fotos al álbum (en loop)
            item.loop_config = {
                tipo: 'subir_fotos_album',
                endpoint_template: `https://graph.facebook.com/v24.0/{{ALBUM_ID}}/photos`,
                body_template: {
                    url: '{{URL_PLACEHOLDER}}',
                    access_token: fbToken
                }
            };

        // REEL (video corto)
        } else if (formato === 'Reel' && tipoContenido === 'video') {
            item.formato_detallado = 'facebook_reel';
            item.url = `https://graph.facebook.com/v24.0/${fbPageId}/video_reels`;
            item.body = {
                upload_phase: 'start',
                file_url: urls[0],
                description: jsonData.facebook_reel?.caption || ''
            };

        // VIDEO POST
        } else if (formato === 'Video Post' && tipoContenido === 'video') {
            item.formato_detallado = 'facebook_video';
            item.url = `https://graph.facebook.com/v24.0/${fbPageId}/videos`;
            item.body = {
                file_url: urls[0],
                description: jsonData.facebook_organico?.copy_completo || ''
            };

        // STORY
        } else if (formato === 'Story') {
            item.formato_detallado = 'facebook_story';
            item.url = `https://graph.facebook.com/v24.0/${fbPageId}/photos`;
            item.body = {
                url: urls[0],
                published: true,
                temporary: true // Para stories
            };
        }
    }

    // ===== TWITTER/X =====
    else if (red.toLowerCase() === 'x' || red.toLowerCase() === 'twitter') {
        const xBearerToken = jsonData.x_twitter?.bearer_token;
        const xApiKey = jsonData.x_twitter?.api_key;
        const xApiSecret = jsonData.x_twitter?.api_key_secret;
        const xAccessToken = jsonData.x_twitter?.access_token;
        const xAccessSecret = jsonData.x_twitter?.access_token_secret;

        if (!xBearerToken) {
            throw new Error('Falta credencial de Twitter/X: bearer_token');
        }

        item.formato_detallado = 'twitter_tweet';
        item.headers = {
            'Authorization': `Bearer ${xBearerToken}`,
            'Content-Type': 'application/json'
        };

        if (cantidadArchivos > 0) {
            // PASO 1: Subir medios (requiere OAuth 1.0a)
            item.total_pasos = 2;
            item.requiere_media_upload = true;

            item.media_upload_config = {
                endpoint: 'https://upload.twitter.com/1.1/media/upload.json',
                oauth_credentials: {
                    api_key: xApiKey,
                    api_secret: xApiSecret,
                    access_token: xAccessToken,
                    access_secret: xAccessSecret
                },
                media_urls: urls
            };

            // PASO 2: Crear tweet con media_ids
            item.url = 'https://api.twitter.com/2/tweets';
            item.body = {
                text: jsonData.x_twitter_tweet?.text || ''
                // media: { media_ids: [] } se agregará después de subir
            };
        } else {
            // Tweet solo texto
            item.url = 'https://api.twitter.com/2/tweets';
            item.body = {
                text: jsonData.x_twitter_tweet?.text || ''
            };
        }
    }

    // ===== YOUTUBE =====
    else if (red.toLowerCase() === 'youtube') {
        const ytToken = jsonData.youtube?.client_secret;

        if (!ytToken) {
            throw new Error('Falta credencial de YouTube: client_secret');
        }

        item.headers = {
            'Authorization': `Bearer ${ytToken}`,
            'Content-Type': 'application/json'
        };

        if (formato === 'Short' && tipoContenido === 'video') {
            item.formato_detallado = 'youtube_short';
            item.url = 'https://www.googleapis.com/upload/youtube/v3/videos';
            item.qs = {
                part: 'snippet,status',
                notifySubscribers: false
            };
            item.body = {
                snippet: {
                    title: jsonData.youtube_short?.titulo || '#Shorts',
                    description: jsonData.youtube_short?.descripcion || '',
                    categoryId: '22',
                    tags: ['Shorts']
                },
                status: {
                    privacyStatus: 'public',
                    selfDeclaredMadeForKids: false
                }
            };

            // URL del video para subir
            item.video_upload_url = urls[0];

        } else if (formato === 'Community Post' && tipoContenido === 'imagen') {
            item.formato_detallado = 'youtube_community';
            item.url = 'https://www.googleapis.com/youtube/v3/posts';
            item.qs = {
                part: 'snippet'
            };
            item.body = {
                snippet: {
                    description: jsonData.youtube_community?.descripcion || ''
                }
            };

            // Imágenes para community post
            item.community_images = urls;
        }
    }

    return item;
}

// ===== GENERAR OUTPUT: UN ITEM POR CADA RED SOCIAL =====
redes.forEach(red => {
    const formatoKey = `${red.toLowerCase()}_formato`;
    const formato = jsonData[formatoKey];

    // Verificar que la red debe publicarse
    const publicarKey = `publicar_${red.toLowerCase()}`;
    if (jsonData[publicarKey] === false || formato?.includes('No publicar')) {
        return; // Saltar esta red
    }

    try {
        const itemData = generarItemPorRed(red, formato);

        // Agregar item con configuración completa
        output.push({
            json: itemData
        });

    } catch (error) {
        // Si falta alguna credencial, agregar item con error
        output.push({
            json: {
                red_social: red.toLowerCase(),
                formato: formato,
                error: true,
                error_message: error.message,
                tipo_contenido: tipoContenido
            }
        });
    }
});

// Si no se generó ningún output, lanzar error
if (output.length === 0) {
    throw new Error('No se generaron items de salida. Verifica que haya redes sociales seleccionadas.');
}

return output;

